// src/components/VideoDetector.js
import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000"; // Your Flask Backend URL

function VideoDetector() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [preview, setPreview] = useState(null);

  const handleFileChange = (event) => {
    const uploadedFile = event.target.files[0];
    setFile(uploadedFile);
    setResult(null);
    setError("");

    if (uploadedFile) {
      setPreview(URL.createObjectURL(uploadedFile));
    } else {
      setPreview(null);
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!file) {
      setError("Please select a video file first.");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    setIsLoading(true);
    setError("");
    setResult(null);

    try {
      // Targets the VIDEO endpoint
      const response = await axios.post(`${API_URL}/predict/video`, formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });

      if (response.data.result === "error") {
        setError(`API Error: ${response.data.message}`);
      } else {
        setResult(response.data);
      }
    } catch (err) {
      setError(
        `Network or Server Error. Ensure Flask is running at ${API_URL}.`
      );
      console.error("Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  const getResultStyle = (prediction) => {
    if (prediction === "DEEPFAKE") {
      return {
        color: "#e74c3c",
        border: "2px solid #e74c3c",
        padding: "10px",
        borderRadius: "5px",
      };
    } else if (prediction === "REAL") {
      return {
        color: "#2ecc71",
        border: "2px solid #2ecc71",
        padding: "10px",
        borderRadius: "5px",
      };
    }
    return {};
  };

  return (
    <div style={{ maxWidth: "700px", margin: "auto" }}>
      <h2>🎥 Deepfake Video Detection</h2>
      <p>
        Upload a video file (MP4, MOV, AVI) to analyze it for deepfake
        manipulation.
      </p>
      <form
        onSubmit={handleSubmit}
        style={{
          display: "flex",
          flexDirection: "column",
          gap: "15px",
          alignItems: "center",
        }}
      >
        <input
          type="file"
          onChange={handleFileChange}
          accept="video/mp4,video/mov,video/avi" // Accepts video files
          style={{
            padding: "10px",
            border: "1px solid #ccc",
            borderRadius: "5px",
          }}
        />
        <button
          type="submit"
          disabled={isLoading || !file}
          style={{
            padding: "10px 20px",
            backgroundColor: "#3498db",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: "pointer",
            opacity: isLoading || !file ? 0.6 : 1,
          }}
        >
          {isLoading ? "Analyzing... Please wait" : "Analyze Video"}
        </button>
      </form>

      {error && <p style={{ color: "red", marginTop: "20px" }}>{error}</p>}

      {preview && (
        <div
          style={{
            marginTop: "30px",
            border: "1px solid #eee",
            padding: "10px",
            borderRadius: "8px",
          }}
        >
          <h3>Video Preview</h3>
          {/* Use the <video> tag for playback */}
          <video
            src={preview}
            controls
            style={{
              maxWidth: "100%",
              maxHeight: "300px",
              borderRadius: "5px",
              display: "block",
              margin: "auto",
            }}
          />
        </div>
      )}

      {result && (
        <div style={{ marginTop: "30px" }}>
          <h3>Analysis Result:</h3>
          <div style={getResultStyle(result.result)}>
            <h4>Prediction: {result.result}</h4>
            <p>Confidence Score: **{(result.confidence * 100).toFixed(2)}%**</p>
          </div>
        </div>
      )}
    </div>
  );
}

export default VideoDetector;
